import { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import { adminApi } from '../../api/admin';
import { Spinner } from '../../components/Spinner';
import type { AdminDashboardDto } from '../../types/admin';

interface Stats {
  totalUsers: number;
  activeUsers: number;
  blockedUsers: number;
  totalOrganizers: number;
  totalVolunteers: number;
  totalEvents: number;
  publishedEvents: number;
  draftEvents: number;
  completedEvents: number;
  cancelledEvents: number;
  totalNews: number;
  publishedNews: number;
  draftNews: number;
  totalParticipations: number;
  pendingParticipations: number;
  approvedParticipations: number;
}

export function AdminDashboard() {
  const [dashboard, setDashboard] = useState<AdminDashboardDto | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const load = async () => {
      try {
        const data = await adminApi.getDashboard();
        setDashboard(data);
      } catch (e) {
        console.error(e);
      } finally {
        setLoading(false);
      }
    };
    load();
  }, []);
      } finally {
        setLoading(false);
      }
    };
    load();
  }, []);

  if (loading) return (
    <div className="flex items-center justify-center h-64">
      <div className="text-center">
        <Spinner />
        <p className="text-gray-500 mt-3">Загрузка статистики...</p>
      </div>
    </div>
  );

  if (!dashboard) {
    return <div className="text-center text-gray-500">Ошибка загрузки данных</div>;
  }

  const stats = dashboard.statistics;
    Draft:     'bg-gray-700 text-gray-300',
    Published: 'bg-green-900/60 text-green-400',
    Cancelled: 'bg-red-900/60 text-red-400',
    Completed: 'bg-blue-900/60 text-blue-400',
  };
  const STATUS_LABEL: Record<string, string> = {
    Draft:'Черновик', Published:'Опубликован', Cancelled:'Отменён', Completed:'Завершён'
  };
  const fmtDate = (s: string) => new Date(s).toLocaleDateString('ru-RU');

  return (
    <div className="space-y-6">
      <div>
        <h1 className="text-2xl font-bold text-white">Дашборд</h1>
        <p className="text-gray-500 text-sm mt-1">Общая статистика системы</p>
      </div>

      {/* STAT CARDS */}
      <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
        {[
          { label:'Всего пользователей', value: stats.totalUsers ?? 0, icon:'fa-users', color:'text-blue-400', bg:'bg-blue-500/10', link:'/admin/users' },
          { label:'Активных',            value: stats.activeUsers ?? 0, icon:'fa-user-check', color:'text-green-400', bg:'bg-green-500/10', link:'/admin/users' },
          { label:'Заблокированных',     value: stats.blockedUsers ?? 0, icon:'fa-user-times', color:'text-red-400', bg:'bg-red-500/10', link:'/admin/users' },
          { label:'Всего мероприятий',   value: stats.totalEvents ?? 0, icon:'fa-calendar-alt', color:'text-purple-400', bg:'bg-purple-500/10', link:'/admin/events' },
        ].map(s => (
          <Link key={s.label} to={s.link} className="bg-gray-900 rounded-2xl p-5 border border-gray-800 hover:border-gray-600 transition no-underline block group">
            <div className="flex items-start justify-between mb-3">
              <div className={`w-10 h-10 ${s.bg} rounded-xl flex items-center justify-center`}>
                <i className={`fas ${s.icon} ${s.color}`} />
              </div>
              <i className="fas fa-arrow-right text-gray-700 group-hover:text-gray-400 transition" />
            </div>
            <div className={`text-3xl font-bold ${s.color} mb-1`}>{s.value}</div>
            <div className="text-gray-500 text-sm">{s.label}</div>
          </Link>
        ))}
      </div>

      {/* EVENT STATUS GRID */}
      <div>
        <h2 className="text-sm font-semibold text-gray-400 uppercase tracking-widest mb-3">Мероприятия по статусу</h2>
        <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
          {[
            { label:'Черновики',    value: stats.draftEvents ?? 0, icon:'fa-pencil-alt', color:'text-gray-400', bg:'bg-gray-700/40', status:'Draft' },
            { label:'Опубликованы', value: stats.publishedEvents ?? 0, icon:'fa-globe', color:'text-green-400', bg:'bg-green-900/30', status:'Published' },
            { label:'Завершены',    value: stats.completedEvents ?? 0, icon:'fa-check-circle', color:'text-blue-400', bg:'bg-blue-900/30', status:'Completed' },
            { label:'Отменены',     value: stats.cancelledEvents ?? 0, icon:'fa-times-circle', color:'text-red-400', bg:'bg-red-900/30', status:'Cancelled' },
          ].map(s => (
            <Link key={s.label} to={`/admin/events?status=${s.status}`} className="bg-gray-900 rounded-xl p-4 border border-gray-800 hover:border-gray-600 transition no-underline block">
              <div className={`w-8 h-8 ${s.bg} rounded-lg flex items-center justify-center mb-2`}>
                <i className={`fas ${s.icon} ${s.color} text-sm`} />
              </div>
              <div className={`text-2xl font-bold ${s.color}`}>{s.value}</div>
              <div className="text-gray-500 text-xs mt-1">{s.label}</div>
            </Link>
          ))}
        </div>
      </div>

      {/* RECENT TABLES */}
      <div className="grid lg:grid-cols-2 gap-6">
        {/* Recent users */}
        <div className="bg-gray-900 rounded-2xl border border-gray-800 overflow-hidden">
          <div className="flex items-center justify-between px-5 py-4 border-b border-gray-800">
            <h3 className="font-semibold text-white text-sm">Последние пользователи</h3>
            <Link to="/admin/users" className="text-primary text-xs hover:underline">Все →</Link>
          </div>
          <div className="divide-y divide-gray-800">
            {recentUsers.length === 0
              ? <p className="text-gray-500 text-sm p-5">Нет данных</p>
              : recentUsers.map(u => {
                  const name = u.firstName ? `${u.firstName}${u.lastName ? ' '+u.lastName : ''}` : u.email.split('@')[0];
                  return (
                    <div key={u.id} className="flex items-center gap-3 px-5 py-3 hover:bg-gray-800/50 transition">
                      {u.avatarUrl
                        ? <img src={u.avatarUrl} alt={name} className="w-8 h-8 rounded-full object-cover flex-shrink-0" />
                        : <div className="w-8 h-8 bg-primary/20 rounded-full flex items-center justify-center flex-shrink-0 text-primary text-xs font-bold">{name.charAt(0).toUpperCase()}</div>
                      }
                      <div className="flex-1 min-w-0">
                        <p className="text-white text-sm font-medium truncate">{name}</p>
                        <p className="text-gray-500 text-xs truncate">{u.email}</p>
                      </div>
                      <div className="flex items-center gap-2 flex-shrink-0">
                        <span className={`px-2 py-0.5 rounded-full text-xs font-medium ${u.role === 'Admin' ? 'bg-purple-900/60 text-purple-400' : u.role === 'Organizer' ? 'bg-blue-900/60 text-blue-400' : 'bg-gray-700 text-gray-400'}`}>
                          {u.role === 'Admin' ? 'Адм.' : u.role === 'Organizer' ? 'Орг.' : 'Вол.'}
                        </span>
                        <span className={`w-2 h-2 rounded-full flex-shrink-0 ${u.isActive ? 'bg-green-500' : 'bg-red-500'}`} />
                      </div>
                    </div>
                  );
                })
            }
          </div>
        </div>

        {/* Recent events */}
        <div className="bg-gray-900 rounded-2xl border border-gray-800 overflow-hidden">
          <div className="flex items-center justify-between px-5 py-4 border-b border-gray-800">
            <h3 className="font-semibold text-white text-sm">Последние мероприятия</h3>
            <Link to="/admin/events" className="text-primary text-xs hover:underline">Все →</Link>
          </div>
          <div className="divide-y divide-gray-800">
            {recentEvents.length === 0
              ? <p className="text-gray-500 text-sm p-5">Нет данных</p>
              : recentEvents.map(ev => (
                  <div key={ev.id} className="flex items-start gap-3 px-5 py-3 hover:bg-gray-800/50 transition">
                    <div className="flex-1 min-w-0">
                      <p className="text-white text-sm font-medium truncate">{ev.title}</p>
                      <p className="text-gray-500 text-xs">{fmtDate(ev.startsAt)} · {ev.location}</p>
                    </div>
                    <span className={`px-2 py-0.5 rounded-full text-xs font-medium flex-shrink-0 ${STATUS_BADGE[ev.status] ?? 'bg-gray-700 text-gray-400'}`}>
                      {STATUS_LABEL[ev.status] ?? ev.status}
                    </span>
                  </div>
                ))
            }
          </div>
        </div>
      </div>

      {/* Quick links */}
      <div>
        <h2 className="text-sm font-semibold text-gray-400 uppercase tracking-widest mb-3">Быстрые действия</h2>
        <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
          {[
            { to:'/admin/events?action=create', icon:'fa-plus-circle', label:'Создать мероприятие', color:'bg-primary/10 text-primary hover:bg-primary/20' },
            { to:'/admin/participations', icon:'fa-clipboard-check', label:'Рассмотреть заявки', color:'bg-amber-500/10 text-amber-400 hover:bg-amber-500/20' },
            { to:'/admin/users', icon:'fa-users-cog', label:'Управление пользователями', color:'bg-blue-500/10 text-blue-400 hover:bg-blue-500/20' },
            { to:'/admin/events', icon:'fa-calendar-check', label:'Все мероприятия', color:'bg-purple-500/10 text-purple-400 hover:bg-purple-500/20' },
          ].map(a => (
            <Link key={a.label} to={a.to} className={`${a.color} rounded-xl p-4 flex flex-col items-center text-center gap-2 transition no-underline`}>
              <i className={`fas ${a.icon} text-2xl`} />
              <span className="text-sm font-medium">{a.label}</span>
            </Link>
          ))}
        </div>
      </div>
    </div>
  );
}

import { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import { adminApi } from '../../api/admin';
import { Spinner } from '../../components/Spinner';
import type { AdminDashboardDto } from '../../types/admin';

interface Stats {
  totalUsers: number;
  activeUsers: number;
  blockedUsers: number;
  totalOrganizers: number;
  totalVolunteers: number;
  totalEvents: number;
  publishedEvents: number;
  draftEvents: number;
  completedEvents: number;
  cancelledEvents: number;
  totalNews: number;
  publishedNews: number;
  draftNews: number;
  totalParticipations: number;
  pendingParticipations: number;
  approvedParticipations: number;
}

export function AdminDashboard() {
  const [dashboard, setDashboard] = useState<AdminDashboardDto | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const load = async () => {
      try {
        const data = await adminApi.getDashboard();
        setDashboard(data);
      } catch (e) {
        console.error(e);
      } finally {
        setLoading(false);
      }
    };
    load();
  }, []);
      } finally {
        setLoading(false);
      }
    };
    load();
  }, []);

  if (loading) return (
    <div className="flex items-center justify-center h-64">
      <div className="text-center">
        <Spinner />
        <p className="text-gray-500 mt-3">Загрузка статистики...</p>
      </div>
    </div>
  );

  if (!dashboard) {
    return <div className="text-center text-gray-500">Ошибка загрузки данных</div>;
  }

  const stats = dashboard.statistics;
    Draft:     'bg-gray-700 text-gray-300',
    Published: 'bg-green-900/60 text-green-400',
    Cancelled: 'bg-red-900/60 text-red-400',
    Completed: 'bg-blue-900/60 text-blue-400',
  };
  const STATUS_LABEL: Record<string, string> = {
    Draft:'Черновик', Published:'Опубликован', Cancelled:'Отменён', Completed:'Завершён'
  };
  const fmtDate = (s: string) => new Date(s).toLocaleDateString('ru-RU');

  return (
    <div className="space-y-6">
      <div>
        <h1 className="text-2xl font-bold text-white">Дашборд</h1>
        <p className="text-gray-500 text-sm mt-1">Общая статистика системы</p>
      </div>

      {/* STAT CARDS */}
      <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
        {[
          { label:'Всего пользователей', value: stats.totalUsers ?? 0, icon:'fa-users', color:'text-blue-400', bg:'bg-blue-500/10', link:'/admin/users' },
          { label:'Активных',            value: stats.activeUsers ?? 0, icon:'fa-user-check', color:'text-green-400', bg:'bg-green-500/10', link:'/admin/users' },
          { label:'Заблокированных',     value: stats.blockedUsers ?? 0, icon:'fa-user-times', color:'text-red-400', bg:'bg-red-500/10', link:'/admin/users' },
          { label:'Всего мероприятий',   value: stats.totalEvents ?? 0, icon:'fa-calendar-alt', color:'text-purple-400', bg:'bg-purple-500/10', link:'/admin/events' },
        ].map(s => (
          <Link key={s.label} to={s.link} className="bg-gray-900 rounded-2xl p-5 border border-gray-800 hover:border-gray-600 transition no-underline block group">
            <div className="flex items-start justify-between mb-3">
              <div className={`w-10 h-10 ${s.bg} rounded-xl flex items-center justify-center`}>
                <i className={`fas ${s.icon} ${s.color}`} />
              </div>
              <i className="fas fa-arrow-right text-gray-700 group-hover:text-gray-400 transition" />
            </div>
            <div className={`text-3xl font-bold ${s.color} mb-1`}>{s.value}</div>
            <div className="text-gray-500 text-sm">{s.label}</div>
          </Link>
        ))}
      </div>

      {/* EVENT STATUS GRID */}
      <div>
        <h2 className="text-sm font-semibold text-gray-400 uppercase tracking-widest mb-3">Мероприятия по статусу</h2>
        <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
          {[
            { label:'Черновики',    value: stats.draftEvents ?? 0, icon:'fa-pencil-alt', color:'text-gray-400', bg:'bg-gray-700/40', status:'Draft' },
            { label:'Опубликованы', value: stats.publishedEvents ?? 0, icon:'fa-globe', color:'text-green-400', bg:'bg-green-900/30', status:'Published' },
            { label:'Завершены',    value: stats.completedEvents ?? 0, icon:'fa-check-circle', color:'text-blue-400', bg:'bg-blue-900/30', status:'Completed' },
            { label:'Отменены',     value: stats.cancelledEvents ?? 0, icon:'fa-times-circle', color:'text-red-400', bg:'bg-red-900/30', status:'Cancelled' },
          ].map(s => (
            <Link key={s.label} to={`/admin/events?status=${s.status}`} className="bg-gray-900 rounded-xl p-4 border border-gray-800 hover:border-gray-600 transition no-underline block">
              <div className={`w-8 h-8 ${s.bg} rounded-lg flex items-center justify-center mb-2`}>
                <i className={`fas ${s.icon} ${s.color} text-sm`} />
              </div>
              <div className={`text-2xl font-bold ${s.color}`}>{s.value}</div>
              <div className="text-gray-500 text-xs mt-1">{s.label}</div>
            </Link>
          ))}
        </div>
      </div>

      {/* RECENT TABLES */}
      <div className="grid lg:grid-cols-2 gap-6">
        {/* Recent users */}
        <div className="bg-gray-900 rounded-2xl border border-gray-800 overflow-hidden">
          <div className="flex items-center justify-between px-5 py-4 border-b border-gray-800">
            <h3 className="font-semibold text-white text-sm">Последние пользователи</h3>
            <Link to="/admin/users" className="text-primary text-xs hover:underline">Все →</Link>
          </div>
          <div className="divide-y divide-gray-800">
            {dashboard.recentParticipations.length === 0
              ? <p className="text-gray-500 text-sm p-5">Нет данных</p>
              : dashboard.recentParticipations.map(u => {
                  const name = u.userName;
                  return (
                    <div key={u.id} className="flex items-center gap-3 px-5 py-3 hover:bg-gray-800/50 transition">
                      <div className="w-8 h-8 bg-primary/20 rounded-full flex items-center justify-center flex-shrink-0 text-primary text-xs font-bold">{name.charAt(0).toUpperCase()}</div>
                      <div className="flex-1 min-w-0">
                        <p className="text-white text-sm font-medium truncate">{name}</p>
                        <p className="text-gray-500 text-xs truncate">{u.eventTitle}</p>
                      </div>
                      <div className="flex items-center gap-2 flex-shrink-0">
                        <span className={`px-2 py-0.5 rounded-full text-xs font-medium ${
                          u.status === 'Approved' ? 'bg-green-900/60 text-green-400' :
                          u.status === 'Rejected' ? 'bg-red-900/60 text-red-400' :
                          'bg-yellow-900/60 text-yellow-400'
                        }`}>
                          {u.status === 'Approved' ? 'Одобрена' : u.status === 'Rejected' ? 'Отклонена' : 'Ожидает'}
                        </span>
                      </div>
                    </div>
                  );
                })
            }
          </div>
        </div>

        {/* Recent events */}
        <div className="bg-gray-900 rounded-2xl border border-gray-800 overflow-hidden">
          <div className="flex items-center justify-between px-5 py-4 border-b border-gray-800">
            <h3 className="font-semibold text-white text-sm">Последние мероприятия</h3>
            <Link to="/admin/events" className="text-primary text-xs hover:underline">Все →</Link>
          </div>
          <div className="divide-y divide-gray-800">
            {dashboard.upcomingEvents.length === 0
              ? <p className="text-gray-500 text-sm p-5">Нет данных</p>
              : dashboard.upcomingEvents.map(ev => (
                  <div key={ev.id} className="flex items-start gap-3 px-5 py-3 hover:bg-gray-800/50 transition">
                    <div className="flex-1 min-w-0">
                      <p className="text-white text-sm font-medium truncate">{ev.title}</p>
                      <p className="text-gray-500 text-xs">{fmtDate(ev.startsAt)} · {ev.location}</p>
                    </div>
                    <span className={`px-2 py-0.5 rounded-full text-xs font-medium flex-shrink-0 ${STATUS_BADGE[ev.status] ?? 'bg-gray-700 text-gray-400'}`}>
                      {STATUS_LABEL[ev.status] ?? ev.status}
                    </span>
                  </div>
                ))
            }
          </div>
        </div>
      </div>

      {/* Quick links */}
      <div>
        <h2 className="text-sm font-semibold text-gray-400 uppercase tracking-widest mb-3">Быстрые действия</h2>
        <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
          {[
            { to:'/admin/events?action=create', icon:'fa-plus-circle', label:'Создать мероприятие', color:'bg-primary/10 text-primary hover:bg-primary/20' },
            { to:'/admin/participations', icon:'fa-clipboard-check', label:'Рассмотреть заявки', color:'bg-amber-500/10 text-amber-400 hover:bg-amber-500/20' },
            { to:'/admin/users', icon:'fa-users-cog', label:'Управление пользователями', color:'bg-blue-500/10 text-blue-400 hover:bg-blue-500/20' },
            { to:'/admin/events', icon:'fa-calendar-check', label:'Все мероприятия', color:'bg-purple-500/10 text-purple-400 hover:bg-purple-500/20' },
          ].map(a => (
            <Link key={a.label} to={a.to} className={`${a.color} rounded-xl p-4 flex flex-col items-center text-center gap-2 transition no-underline`}>
              <i className={`fas ${a.icon} text-2xl`} />
              <span className="text-sm font-medium">{a.label}</span>
            </Link>
          ))}
        </div>
      </div>
    </div>
  );
}

import { useCallback, useEffect, useState } from 'react';
import { adminApi } from '../../api/admin';
import { Spinner } from '../../components/Spinner';
import type { AdminEventListDto, AdminEventStatisticsDto } from '../../types/admin';

const TAKE = 20;

const STATUS_LABEL: Record<string, string> = {
  Draft: 'Черновик',
  Published: 'Опубликован',
  Cancelled: 'Отменён',
  Completed: 'Завершён',
};

const STATUS_COLOR: Record<string, string> = {
  Draft: 'bg-gray-700 text-gray-300',
  Published: 'bg-green-900/60 text-green-400',
  Cancelled: 'bg-red-900/60 text-red-400',
  Completed: 'bg-blue-900/60 text-blue-400',
};

interface StatsModalProps {
  event: AdminEventListDto;
  onClose: () => void;
}

function StatsModal({ event, onClose }: StatsModalProps) {
  const [stats, setStats] = useState<AdminEventStatisticsDto | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const load = async () => {
      try {
        const data = await adminApi.getEventStatistics(event.id);
        setStats(data);
      } catch (e) {
        console.error('Error loading event statistics:', e);
      } finally {
        setLoading(false);
      }
    };
    load();
  }, [event.id]);

  if (loading) {
    return (
        <div className="flex items-center justify-center py-8">
          <Spinner />
        </div>
    );
  }

  if (!stats) {
    return <div className="text-center text-gray-500">Ошибка загрузки статистики</div>;
  }

  return (
      <div className="space-y-4">
        <div>
          <h3 className="text-white font-medium mb-3">{event.title}</h3>
          <div className="grid grid-cols-2 gap-3">
            <div className="p-3 bg-gray-800 rounded-lg">
              <p className="text-gray-400 text-xs">Всего заявок</p>
              <p className="text-white text-lg font-bold">{stats.totalApplications}</p>
            </div>
            <div className="p-3 bg-gray-800 rounded-lg">
              <p className="text-gray-400 text-xs">Одобрено</p>
              <p className="text-green-400 text-lg font-bold">{stats.approvedParticipants}</p>
            </div>
            <div className="p-3 bg-gray-800 rounded-lg">
              <p className="text-gray-400 text-xs">Отклонено</p>
              <p className="text-red-400 text-lg font-bold">{stats.rejectedParticipants}</p>
            </div>
            <div className="p-3 bg-gray-800 rounded-lg">
              <p className="text-gray-400 text-xs">Посещение подтверждено</p>
              <p className="text-blue-400 text-lg font-bold">{stats.attendanceConfirmed}</p>
            </div>
            <div className="p-3 bg-gray-800 rounded-lg col-span-2">
              <p className="text-gray-400 text-xs mb-1">Процент заполнения</p>
              <div className="flex items-center gap-2">
                <div className="flex-1 h-2 bg-gray-700 rounded-full overflow-hidden">
                  <div
                      className="h-full bg-primary transition-all"
                      style={{ width: `${Math.min(stats.fillPercentage, 100)}%` }}
                  />
                </div>
                <span className="text-white font-medium text-sm">{stats.fillPercentage.toFixed(1)}%</span>
              </div>
            </div>
            {stats.freeSlots > 0 && (
                <div className="p-3 bg-gray-800 rounded-lg col-span-2">
                  <p className="text-gray-400 text-xs">Свободных мест</p>
                  <p className="text-blue-400 text-lg font-bold">{stats.freeSlots}</p>
                </div>
            )}
          </div>
        </div>

        <button
            onClick={onClose}
            className="w-full px-4 py-2 bg-gray-700 hover:bg-gray-600 text-white font-medium rounded-lg transition"
        >
